INSERT INTO vulnerability_candidates ("vulnerabilityCandidateId","scanJobId",title,description,"filePath",line,status,"currentStage",confidence,score,"createdAt","updatedAt") VALUES
('ZMvH_YQJ-l332GJnV71hN','SzL-qPTgyVnJq71i9jat4','Bare tkeyname command leaves dangling GSS-TSIG key name pointer','The tkeyname dispatcher branch frees the previous user_tkey_name before parsing a replacement, but if no new token is supplied it leaves the global pointer non-NULL. Later GSS-TSIG setup copies from the freed pointer and shutdown frees it again, creating a plausible local UAF/double-free path from command input.','bin/nsupdate/nsupdate.c',2333,'queued','analyzing',0.94,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('ZhiESszKZW9rdc5FHGayW','SzL-qPTgyVnJq71i9jat4','Malformed dnstap address length can reach inet_ntop() as an undersized IPv6 buffer','print_yaml() treats any non-4-byte address blob as IPv6 and passes ip->data directly to inet_ntop(AF_INET6, ...). A crafted dnstap file with a short query_address or response_address can trigger an out-of-bounds read during YAML rendering.','bin/tools/dnstap-read.c',278,'queued','analyzing',0.91,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('rwSgqeXQRFT_3dOypPJUm','SzL-qPTgyVnJq71i9jat4','Unescaped identity and version fields can inject structure into YAML output','print_yaml() emits frame->identity and frame->version as raw scalars without YAML escaping or quoting. A malicious dnstap record can add newlines or YAML metacharacters that mislead downstream parsers or consumers of the generated YAML stream.','bin/tools/dnstap-read.c',212,'queued','analyzing',0.77,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('nUucNwWLYpMXmO7rabVov','SzL-qPTgyVnJq71i9jat4','Failed key directive can silently disable GSS-TSIG','The command dispatcher clears usegsstsig before evaluate_key() succeeds, and interactive syntax errors are recoverable, so a malformed key command can downgrade later UPDATE authentication away from the prior GSS-TSIG mode.','bin/nsupdate/nsupdate.c',2307,'queued','analyzing',0.85,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('tnQDU7xFmfVSF_c6yJOgI','SzL-qPTgyVnJq71i9jat4','TSIG replacement failure clears existing signer','evaluate_key() detaches the old tsigkey before dns_tsigkey_create() succeeds. On failure it returns STATUS_SYNTAX with tsigkey cleared, and the interactive loop may later send an unsigned UPDATE.','bin/nsupdate/nsupdate.c',1727,'queued','analyzing',0.91,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('tK4feDhblRXqfR0Iw-9Ju','SzL-qPTgyVnJq71i9jat4','Empty zone command preserves previous explicit zone selection','If a prior valid zone was set, the missing-argument path returns STATUS_SYNTAX without clearing userzone. Interactive mode continues after syntax errors, so a later send can still target the stale zone.','bin/nsupdate/nsupdate.c',1748,'queued','analyzing',0.75,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('_rRW3WryICRGF88Gbua4K','SzL-qPTgyVnJq71i9jat4','Null parameter dereference in plugin_check validation path','plugin_check calls strlen(parameters) without checking for NULL, but the plugin config walker may pass NULL when the optional parameters clause is omitted.','bin/plugins/filter-a.c',360,'queued','analyzing',0.93,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('EYMmumzaX9HWvDV6S-GO1','SzL-qPTgyVnJq71i9jat4','Serial truncation on compact argument may steer journal rewrite to the wrong transaction','The -c argument is parsed with strtoul() and assigned to unsigned int without an overflow check. On platforms where unsigned long is wider than 32 bits, oversized values can be accepted, truncated, and then passed into dns_journal_compact(), which uses 32-bit serial semantics for journal range and rewrite selection.','bin/tools/named-journalprint.c',65,'queued','analyzing',0.75,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('GlPQmu0qMNVsTJIVsyqZh','SzL-qPTgyVnJq71i9jat4','Uninitialized success return may misreport TSIG config parse outcome','read_confkey() returns the local result variable without initializing it on the all-success path, so setup_file_key() may branch on stack garbage after a successful session-key parse.','bin/dig/dighost.c',1089,'queued','analyzing',0.9,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('tNsz1s_6wGJC0YRM803Io','SzL-qPTgyVnJq71i9jat4','TSIG name and secret are silently truncated when loaded from config','The parser copies keyname and secretstr into fixed-size global buffers with strlcpy() and never checks for truncation before setup_text_key() decodes and instantiates the TSIG key from the shortened values.','bin/dig/dighost.c',1079,'queued','analyzing',0.62,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('6LNiNZeNxeS-IA1qBpbzm','SzL-qPTgyVnJq71i9jat4','Oversized LMDB record length can bypass printf bounds via int truncation','main() casts key.mv_size and data.mv_size from size_t to int before using them as %.*s precisions. A crafted NZD entry larger than INT_MAX can turn the precision negative, causing printf to treat the string as unbounded and read past the LMDB value until a NUL byte is found.','bin/tools/named-nzd2nzf.c',90,'queued','analyzing',0.87,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('TVmndpYRTzy2XUmvRl-qs','SzL-qPTgyVnJq71i9jat4','Shallow-cloned EDNS option array can double-free across queued queries','clone_default_query() memmoves default_query into each new query but does not deep-copy ednsopts or nested value buffers. parse_args() can therefore queue multiple queries that share one EDNS option allocation, which is later reused and freed once per query.','bin/tools/mdig.c',1760,'queued','analyzing',0.96,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('pFLbfMohHZLtp6x0D9dEB','SzL-qPTgyVnJq71i9jat4','Shared global COOKIE buffer can rewrite already-queued query state','plus_option() stores +cookie data in the global hexcookie buffer and points query->cookie at it. When parse_args() queues multiple queries, later cookie parsing can overwrite the cookie contents for earlier queued queries before sendquery() uses them.','bin/tools/mdig.c',1239,'queued','analyzing',0.67,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('tqcqtW1eLyG4HvL2j3B0I','SzL-qPTgyVnJq71i9jat4','Keystore option check drops configured key-directory fallback','check_keystore_options() resolves the keystore directory with a NULL fallback, so policy-driven key generation can discard the caller''s configured key-directory (such as -K) and later fall back to ''.''. This can redirect private key writes and collision checks into the current working directory instead of the validated target directory.','bin/dnssec/dnssec-keygen.c',741,'queued','analyzing',0.93,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('IZl3TYWqiHT-h82s0WCHD','SzL-qPTgyVnJq71i9jat4','NSEC3 CLI path accepts iteration counts far above library policy','The main() entry point forwards user-controlled iteration values into nsec3hash(), which only rejects values above 65535 before invoking isc_iterated_hash(). This is inconsistent with the DNS library''s DNS_NSEC3_MAXITERATIONS limit of 50 and may expose CPU-heavy hashing when the tool is driven by untrusted or automated input.','bin/tools/nsec3hash.c',106,'queued','analyzing',0.46,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('4cFeiiYGTMsoGDpxMyz86','SzL-qPTgyVnJq71i9jat4','Full-trace listener accepts arbitrary loopback clients into the active resolver view','run_server() opens a loopback TCP DNS listener and pairs it with matchview(), which unconditionally assigns the active resolver view. A concurrent local process may be able to connect before shutdown and inject its own DNS request flow through this path.','bin/delv/delv.c',2195,'queued','analyzing',0.36,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('wvRSBKJTlQkI8g7LtAO90','SzL-qPTgyVnJq71i9jat4','Malformed stdin import can exit with DB still in active load state','If dns_master_loadstream() rejects zone text, the function aborts before dns_db_endload() runs. That diverges from the documented beginload/endload contract and from dns_db_load(), leaving qpzone load state and callbacks->add_private cleanup unfinished on the stdin parser path.','bin/dnssec/dnssec-importkey.c',84,'queued','analyzing',0.79,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('CXGuY7VnH09rho2WS4WPa','SzL-qPTgyVnJq71i9jat4','Imported DNSKEY can overwrite unrelated external key files on key-tag collision','emit() uses the filename tuple derived from owner name, algorithm, and key tag to identify pre-existing key files. Because the overwrite gate only rejects non-external private keys, a colliding imported DNSKEY can replace a different external/imported key''s .key and placeholder .private files without verifying full-key equality.','bin/dnssec/dnssec-importkey.c',218,'queued','analyzing',0.82,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('1ukLEtn-SegbYL0FAkcXe','SzL-qPTgyVnJq71i9jat4','Unchecked COOKIE optlen can read past remaining OPT bytes and assert on forward','A malformed OPT RR can advertise a COOKIE option length larger than the bytes left in the OPT buffer. process_cookie() then compares and copies from isc_buffer_current(optbuf) using the unchecked length context and finally calls isc_buffer_forward(optbuf, optlen), making truncated responses a plausible out-of-bounds read or assertion-triggering path.','bin/dig/dighost.c',3745,'queued','analyzing',0.9,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('S4n6uLJWJix6WukuO2vlD','SzL-qPTgyVnJq71i9jat4','Successor rollover metadata is written non-atomically','The predecessor key is updated on disk before the new successor key is persisted, so a later write failure can leave on-disk rollover metadata pointing at a nonexistent successor.','bin/dnssec/dnssec-keygen.c',704,'queued','analyzing',0.82,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('JQ-qcBW10GzMpw8xmKVCK','SzL-qPTgyVnJq71i9jat4','Delete-before-inactive key lifecycle is only warned','The function warns but still stores a deletion time earlier than the inactive time, permitting a key state that can remove key material before rollover or retirement completes.','bin/dnssec/dnssec-keygen.c',634,'queued','analyzing',0.67,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('kw2xhVfdcA1ZmAAmAfvff','SzL-qPTgyVnJq71i9jat4','Null dereference when filter-aaaa plugin parameters are omitted','The config validation path calls strlen(parameters) and cfg_parse_buffer() without checking for NULL, but the plugin framework passes NULL when the optional parameters field is absent.','bin/plugins/filter-aaaa.c',364,'queued','analyzing',0.94,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z'),
('fftTLkrGiRNzCpw2W5e3u','SzL-qPTgyVnJq71i9jat4','Oversized batch command lines are silently split by fixed-size fgets() reads','get_next_command treats each fgets() chunk as a complete command and never detects missing newline termination. A line longer than MAXCMD-1 bytes is parsed as multiple commands or can force a fatal syntax error in batch mode.','bin/nsupdate/nsupdate.c',2414,'queued','analyzing',0.72,NULL,'2026-04-24T07:48:39.384106Z','2026-04-24T07:48:39.384106Z');
